const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

#### 3. No Input Validation or Sanitization
No `express.json()` body parser or any validation is in place. If POST/PUT routes are added later, raw untrusted input would be processed directly.

```js
app.use(express.json({ limit: '10kb' })); // Parse JSON with a size cap
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

---

### 🟠 Moderate Issues

#### 4. No Global Error Handling Middleware
Unhandled errors will crash the process or leak stack traces to clients.

```js
// Catch-all 404
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// Global error handler (must have 4 params for Express to treat as error handler)
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message, // Don't leak details in production
  });
});
```

#### 5. No CORS Policy
Without explicit CORS configuration, browser-based cross-origin requests behave unpredictably and can be either too open or too restrictive.

```js
// Add: npm install cors
const cors = require('cors');
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? [],
  methods: ['GET'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));
```

#### 6. Hardcoded Port
Port `3000` is hardcoded. This makes deployment inflexible and prevents environment-based configuration.

```js
const PORT = parseInt(process.env.PORT ?? '3000', 10);
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

---

### 🟡 Minor / Best Practice Issues

#### 7. No Request Logging
No visibility into who is calling what, making incident response and debugging very difficult.

```js
// Add: npm install morgan
const morgan = require('morgan');
app.use(morgan('combined')); // Apache-style logs; pipe to a log aggregator in prod
```

#### 8. No Graceful Shutdown
The server doesn't handle `SIGTERM`/`SIGINT`, which can cause dropped requests during container restarts or deploys.

```js
const server = app.listen(PORT, () => console.log(`Server running on port ${PORT}`));

process.on('SIGTERM', () => {
  server.close(() => {
    console.log('Server shut down gracefully');
    process.exit(0);
  });
});
```

#### 9. `/users` Leaks Data Shape
Even with hardcoded data, returning a flat list with no pagination or field filtering sets a risky precedent. Future real-data routes should:
- Paginate responses (`?page=1&limit=20`)
- Return only necessary fields (avoid exposing `passwordHash`, internal IDs, etc.)
- Validate and sanitize any query parameters

